#!/usr/bin/env node
// DROP8_REFACTOR_013H1_LARGE_NESTED_ROOM_WINDOW_DOCK8_TERRAIN_LOOT
import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';
import zlib from 'node:zlib';
import { spawnSync } from 'node:child_process';

type FileKind='modify'|'create';
type FileRecord={path:string;kind:FileKind;before:string;after:string;data:string};
const PATCH='Refactor 013H1';
const DRY=process.argv.includes('--dry-run');
const SKIP=process.env.DROP8_PATCH_SKIP_EXTERNAL_VALIDATION==='1';
const FORCE_FAILURE=process.env.DROP8_PATCH_FORCE_VALIDATION_FAILURE==='1';
const BACKUP_DIR='patch_backups/refactor_013H1_large_map_nested_room_window_dock8_terrain_loot_hotfix';
const FILES:FileRecord[]=[{"path":"README.md","kind":"modify","before":"0d9f3519b98b787563978f626b82b866b833627801074f90ce66af7e36c9a8f2","after":"48614413fa24ccad1bc00618356770a23519953eacf507643c05548fbfb94433","data":""},{"path":"client/src/GameScene.ts","kind":"modify","before":"c301389ad3b1eff28a0190e4920c7149c3143a1ac44b9886c332b4f2cf0ab9c8","after":"6e0f33e03068b46226fdbf620bddeeb2ee206532e5557cc0bb6fb14120c676d2","data":""},{"path":"docs/PATCH_NOTES.md","kind":"modify","before":"39f19ae356b2cc526751127cb663a3dce91ed16076cd9dbd3efe3d979edb69dd","after":"02fb563b769e6e52eed544046095aee99729d58acd9163db620f6bdbeac26a97","data":""},{"path":"docs/TEST_PLAN.md","kind":"modify","before":"31722426b69e4f16016f4d8fc31fc525425f925b84b3e7daace433dc7ebead90","after":"2ba801cc1d15f26b244977e09f3bc2ce5d6d62e1b57ff5ee174365d7827ec746","data":""},{"path":"server/src/rooms/Drop8Room.ts","kind":"modify","before":"c6357fafb66e028532a7f219bf4f0e4d94d42e297701641c0768a0e4b35ec0a2","after":"30d6f17c8606e3fefb774780c29a8eacab023e5e45ae5eccf4fc85aea3d577d5","data":""},{"path":"server/tests/refactor013h-visibility-roof-source.test.ts","kind":"modify","before":"ce1a61b0e292f47706abf9b3f6e420eeb324116d3f6c0cc35827ce1f33e20ca7","after":"f9c33554f41efee1896f19e9c99fbed2e9538423a1f32acccba825c5f07843af","data":""},{"path":"shared/src/index.ts","kind":"modify","before":"f251266f86a1b999bfc2f7e315dee564ba029879145ac2d90ae8a144847960bd","after":"23645a73bb24c174e34d6a269fd16ebe0b658abce3bc50914aad437047080824","data":""},{"path":"shared/src/maps/dock8.ts","kind":"modify","before":"72a2b4eb12374b9391a4909d3ae6d64990ca55536483feffe84c99ad5c62679d","after":"f00b9fb267d085d24671ae2fe1da22546f31a6ce6d0725af8717d835b2ea7e4e","data":""},{"path":"shared/src/maps/rooms.ts","kind":"modify","before":"cf8e5d2a4c883dece4ad660c434fc17c89d397570a5ccf258bb0aa3c7b88d033","after":"e3e80be910396b516b7017b0b024a396d55ec069b67e2a72722a31d2365bb15f","data":""},{"path":"shared/src/maps/types.ts","kind":"modify","before":"2173182b9ef077dd96e78fb30785763270ce9b31a08ce4bba26aed0ca8e9c250","after":"c916ec141293d21bc17d5a0f7805f33460233f83f9b008c58fd04e24b4a465b4","data":""},{"path":"server/tests/refactor013h1-nested-window-dock8-loot.test.ts","kind":"create","before":"","after":"6ae4e70877bd03394243989dbf8fa53cd66ace81d022121951025176363770db","data":""},{"path":"shared/tests/refactor013h1-room-dock8.test.ts","kind":"create","before":"","after":"7d5796c8dc73a3def0e8a151490e8a2ad0ed0ee04c5c9f2ffa41e42fc51e26e4","data":""}];

function hash(data:Buffer|string){return crypto.createHash('sha256').update(data).digest('hex');}
function decode(data:string){return zlib.gunzipSync(Buffer.from(data,'base64'));}
function findRoot(start=process.cwd()){
  let current=path.resolve(start);
  for(let index=0;index<12;index++){
    if(fs.existsSync(path.join(current,'package.json'))&&fs.existsSync(path.join(current,'shared','src','index.ts'))&&fs.existsSync(path.join(current,'client','src','GameScene.ts'))&&fs.existsSync(path.join(current,'server','src','rooms','Drop8Room.ts')))return current;
    const parent=path.dirname(current);if(parent===current)break;current=parent;
  }
  throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 프로젝트 최상위 폴더에서 실행하세요.');
}
function currentHash(file:string){return fs.existsSync(file)?hash(fs.readFileSync(file)):'';}
function writeAtomic(file:string,data:Buffer){
  fs.mkdirSync(path.dirname(file),{recursive:true});
  const tmp=`${file}.013h1.tmp-${process.pid}`;
  fs.writeFileSync(tmp,data);
  try{fs.renameSync(tmp,file);}
  catch{fs.copyFileSync(tmp,file);fs.rmSync(tmp,{force:true});}
}
function printable(command:string,args:string[]){return [command,...args].map((part)=>/\s|["&|<>^]/.test(part)?`"${part.replaceAll('"','\"')}"`:part).join(' ');}
function run(root:string,command:string,args:string[],required=true){
  console.log(`[${PATCH}] ${printable(command,args)}`);
  const result=process.platform==='win32'
    ?spawnSync('cmd.exe',['/d','/s','/c',printable(command,args)],{cwd:root,stdio:'inherit',windowsHide:true})
    :spawnSync(command,args,{cwd:root,stdio:'inherit'});
  if(result.error){if(required)throw result.error;return false;}
  if(result.status!==0){if(required)throw new Error(`${command} ${args.join(' ')} 실패 (exit=${result.status})`);return false;}
  return true;
}
function count(text:string,needle:string){return text.split(needle).length-1;}
function validateSemantic(root:string){
  const read=(relative:string)=>fs.readFileSync(path.join(root,relative),'utf8');
  const types=read('shared/src/maps/types.ts');
  const rooms=read('shared/src/maps/rooms.ts');
  const shared=read('shared/src/index.ts');
  const dock=read('shared/src/maps/dock8.ts');
  const game=read('client/src/GameScene.ts');
  const server=read('server/src/rooms/Drop8Room.ts');
  const sharedTest=read('shared/tests/refactor013h1-room-dock8.test.ts');
  const serverTest=read('server/tests/refactor013h1-nested-window-dock8-loot.test.ts');
  const sourceTest=read('server/tests/refactor013h-visibility-roof-source.test.ts');
  for(const [label,text,markers] of [
    ['types',types,['DROP8_REFACTOR_013H1_LARGE_NESTED_ROOM_WINDOW_DOCK8_TERRAIN_LOOT','sideABuildingId?:string','sideBBuildingId?:string']],
    ['rooms',rooms,['buildingZonesAt','spaceAtExcludingBuilding','portalBuildingIdForSide','portalTraversalCandidates','roomArea(a)-roomArea(b)']],
    ['shared',shared,['buildingZonesAt','portalBuildingIdForSide','lootBudget:85','lootBudget:142','lootBudget:280']],
    ['dock8',dock,['anchorNoise','gridAnchors','slice(0,380)']],
    ['client',game,['resolvedViewerSpace','buildingZonesAt','drawJoinedLayer','cutViewerFromVisionOverlay','Duplicate roof for building']],
    ['server',server,['resolveVaultDestination','dock8?32:18','terrainKindAt','portalBuildingIdForSide']],
    ['shared test',sharedTest,['selects the smallest matching room','keeps Dock 8 river bends deep-water','lootBudget).toBe(280)']],
    ['server test',serverTest,['20 alternating server-authoritative vaults','seed<=500','toHaveLength(280)']],
    ['source test',sourceTest,['buildingZonesAt','cutViewerFromVisionOverlay','drawJoinedLayer']],
  ] as const)for(const marker of markers)if(!text.includes(marker))throw new Error(`${label} 의미 검증 실패: ${marker}`);
  if(count(shared,'lootBudget:85')!==1||count(shared,'lootBudget:142')!==1||count(shared,'lootBudget:280')!==1)throw new Error('맵별 전리품 budget이 예상과 다릅니다.');
  if(count(game,'buildingRoofs.set(zone.id,roof)')!==1)throw new Error('Building roof 등록 경로가 정확히 하나가 아닙니다.');
  if(/buildingRoofs\.set\([^)]*room/i.test(game))throw new Error('RoomZone이 roof key로 사용되고 있습니다.');
  if(!dock.includes('170 indoor')&&!dock.includes('170개'))throw new Error('Dock 8 실내 앵커 기준 설명이 누락되었습니다.');
}
function externalValidation(root:string){
  if(SKIP){console.log(`[${PATCH}] DROP8_PATCH_SKIP_EXTERNAL_VALIDATION=1: 개발용 외부 검증 생략`);if(FORCE_FAILURE)throw new Error('강제 검증 실패 테스트');return;}
  run(root,'pnpm',['run','typecheck']);
  run(root,'pnpm',['run','lint']);
  console.log(`[${PATCH}] 큰 맵 방·Dock 8 공용 테스트`);
  run(root,'pnpm',['--filter','@drop8/shared','exec','vitest','run','tests/refactor013h1-room-dock8.test.ts','--reporter=verbose']);
  console.log(`[${PATCH}] 큰 맵 창문 양방향 20회 + Dock 8 전리품 500시드 테스트`);
  run(root,'pnpm',['--filter','@drop8/server','exec','vitest','run','tests/refactor013h1-nested-window-dock8-loot.test.ts','--pool=threads','--maxWorkers=1','--no-file-parallelism','--testTimeout=60000','--hookTimeout=30000','--reporter=verbose']);
  run(root,'pnpm',['run','test']);
  run(root,'pnpm',['run','build']);
  if(run(root,'git',['rev-parse','--is-inside-work-tree'],false))run(root,'git',['diff','--check']);
  if(FORCE_FAILURE)throw new Error('강제 검증 실패 테스트');
}
function main(){
  const root=findRoot();
  console.log(`[${PATCH}] 프로젝트 루트: ${root}`);
  const states=FILES.map((record)=>{
    const file=path.join(root,record.path),got=currentHash(file);
    if(got===record.after)return'after';
    if(record.kind==='modify'&&got===record.before)return'before';
    if(record.kind==='create'&&!got)return'before';
    throw new Error(`기준 검증 실패: ${record.path}
예상 FIXED v3=${record.before||'(없음)'}
예상 013H1=${record.after}
현재=${got||'(없음)'}`);
  });
  if(states.every((state)=>state==='after')){console.log(`[${PATCH}] 이미 완전히 적용되어 있습니다.`);return;}
  if(states.some((state)=>state==='after'))throw new Error('부분 적용 상태가 감지되었습니다. 자동 덮어쓰기를 중단합니다.');
  console.log(`[${PATCH}] FIXED v3 기준 검증 성공: 기존 파일 ${FILES.filter((file)=>file.kind==='modify').length}개 수정, 신규 테스트 ${FILES.filter((file)=>file.kind==='create').length}개 생성 예정`);
  console.log(`[${PATCH}] 큰 맵: 중첩 Building·RoomZone 현재 공간 선택, 부모/자식 지붕 reveal, 외벽·내부 창문 양방향 vault`);
  console.log(`[${PATCH}] Dock 8 지형: 서버 캡슐형 RiverBand와 동일한 joined-stroke 수면 렌더링`);
  console.log(`[${PATCH}] Dock 8 전리품: 활성 216 → 280, 실내 170(60.7%), seed 기반 자연 분산`);
  console.log(`[${PATCH}] 미변경: 작은 맵 전리품 85, 큰 맵 전리품 142, 오토바이 8대, FIXED v3 AI·자기장·저격총 가중치`);
  console.log(`[${PATCH}] 검증: 창문 양방향 20회, Dock 8 500시드, 전체 typecheck/lint/test/build/git diff`);
  if(DRY){console.log(`[${PATCH}] dry-run 성공. 원본·백업·테스트 파일을 수정하거나 생성하지 않았습니다.`);return;}
  const backup=path.join(root,BACKUP_DIR);
  const stage=path.join(root,`patch_backups/.tmp_refactor_013H1_${process.pid}`);
  const originals=new Map<string,Buffer|undefined>();
  fs.mkdirSync(backup,{recursive:true});fs.mkdirSync(stage,{recursive:true});
  try{
    for(const record of FILES){
      const file=path.join(root,record.path);
      originals.set(record.path,fs.existsSync(file)?fs.readFileSync(file):undefined);
      const payload=decode(record.data);
      if(hash(payload)!==record.after)throw new Error(`내장 payload 해시 불일치: ${record.path}`);
      writeAtomic(path.join(stage,record.path),payload);
      if(record.kind==='modify')writeAtomic(path.join(backup,'preimage',record.path),fs.readFileSync(file));
    }
    validateSemantic(stage);
    fs.writeFileSync(path.join(backup,'manifest.json'),JSON.stringify({patch:'013H1',createdAt:new Date().toISOString(),files:FILES.map((file)=>({path:file.path,kind:file.kind,before:file.before,after:file.after}))},null,2));
    for(const record of FILES)writeAtomic(path.join(root,record.path),fs.readFileSync(path.join(stage,record.path)));
    validateSemantic(root);
    externalValidation(root);
    for(const record of FILES){const got=currentHash(path.join(root,record.path));if(got!==record.after)throw new Error(`적용 후 해시 불일치: ${record.path}`);}
    console.log(`[${PATCH}] 적용과 모든 필수 검증이 성공했습니다.`);
    console.log(`[${PATCH}] 백업: ${backup}`);
  }catch(error){
    console.error(`[${PATCH}] 실패. 변경 파일을 FIXED v3 적용 직전 상태로 자동 롤백합니다.`);
    for(const record of [...FILES].reverse()){
      const file=path.join(root,record.path),original=originals.get(record.path);
      if(original===undefined){if(fs.existsSync(file))fs.rmSync(file,{force:true});}
      else writeAtomic(file,original);
    }
    throw error;
  }finally{fs.rmSync(stage,{recursive:true,force:true});}
}
try{main();}catch(error){console.error(`[${PATCH}] 오류: ${error instanceof Error?error.message:String(error)}`);process.exitCode=1;}
